<?php namespace App\Repositories\Assessment;use App\Repositories\BaseRepository;use App\Models\Assessment\ContinuousAssessment;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class ContinuousAssessmentRepository extends BaseRepository{    public function __construct(ContinuousAssessment $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findBySubject(int $subjectId): Collection    {        return $this->findByField('subject_id', $subjectId);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findByAssessmentType(string $type): Collection    {        return $this->findByField('assessment_type', $type);    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('assessment_date', [$startDate, $endDate])->get();    }    public function getStudentAverage(int $studentId, int $subjectId): float    {        return $this->query()->where('student_id', $studentId)->where('subject_id', $subjectId)->avg('marks_obtained') ?? 0;    }    public function getClassAverage(int $classId, int $subjectId): float    {        return $this->query()->where('class_id', $classId)->where('subject_id', $subjectId)->avg('marks_obtained') ?? 0;    }    public function getByStudentAndSubject(int $studentId, int $subjectId): Collection    {        return $this->query()->where('student_id', $studentId)->where('subject_id', $subjectId)->orderBy('assessment_date', 'asc')->get();    }    public function getTermAssessments(int $termId): Collection    {        return $this->findByField('term_id', $termId);    }}